import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    def calculate_penalty_based_on_time_window(arrival_time, time_window):
        start_window, end_window = time_window
        if arrival_time < start_window:
            return (start_window - arrival_time) * 2
        elif arrival_time > end_window:
            return (arrival_time - end_window) * 20
        return 0

    def calculate_proximity_score(all_truck_positions, target_position):
        return sum(calculate_distance(pos, target_position) for pos in all_truck_positions) / len(all_truck_positions)

    def adjust_dynamic_weight(distance, penalty, proximity, performance_history):
        # Simple heuristic to modify weights based on past performance
        if performance_history['delay_penalty'] > performance_history['proximity_penalty']:
            proximity_weight = 0.3
            penalty_weight = 1
        else:
            proximity_weight = 0.5
            penalty_weight = 0.5
        return distance + penalty_weight * penalty - proximity_weight * proximity

    performance_history = {'delay_penalty': 1, 'proximity_penalty': 1}  # Could be updated in real usage based on actual metrics logged

    scores = []

    for idx, customer in enumerate(unvisited_customers):
        travel_time_to_customer = calculate_distance(cur_truck_pos, customer) / truck_speed
        arrival_time_to_customer = current_time + travel_time_to_customer
        penalty_time = calculate_penalty_based_on_time_window(arrival_time_to_customer, time_windows[idx])
        proximity_score = calculate_proximity_score(all_truck_pos, customer)

        score = adjust_dynamic_weight(travel_time_to_customer, penalty_time, proximity_score, performance_history)
        scores.append(score)

    best_node = np.argmin(scores)
    return best_node
